 use jwxt;
 #代码开始
 #第一题
select studentid, name from student where sex = '男';
 #第二题
select name, nativeplace from student
where nativeplace in ('湖南', '湖北');
 #第三题
 select name, birthday from student
where 2025-year(birthday) in (28,29,30);
 #第四题
select * from student
where sex = '男' and nativeplace = '湖南';
 #第五题
select * from student
 where sex = '男' or
       nativeplace = '湖南';
 #代码结束
